+    /**
+     * Wire hover preview on a stamp container.
+     * @param {St.Widget} container
+     * @param {Meta.Window} metaWindow
+     */
+    wireHoverPreview(container, metaWindow) {
+        container.connect('enter-event', () => {
+            this._showPreview(metaWindow, container);
+            return Clutter.EVENT_PROPAGATE;
+        });
+        container.connect('leave-event', () => {
+            this._hidePreview();
+            return Clutter.EVENT_PROPAGATE;
+        });
+    }
+
+    _showPreview(metaWindow, container) {
+        this._hidePreview();
+
+        const actor = metaWindow.get_compositor_private();
+        if (!actor)
+            return;
+
+        const frameRect = metaWindow.get_frame_rect();
+
+        // Clone at full size
+        const clone = new Clutter.Clone({
+            source: actor,
+            width: frameRect.width,
+            height: frameRect.height,
+            reactive: false,
+        });
+
+        this._previewContainer = new St.Widget({
+            style_class: 'mutter-butter-hover-preview',
+            reactive: false,
+            width: frameRect.width,
+            height: frameRect.height,
+        });
+        this._previewContainer.add_child(clone);
+
+        // Position: above the stamp, clamped to screen
+        const [stampX, stampY] = container.get_transformed_position();
+        const monGeo = global.display.get_monitor_geometry(metaWindow.get_monitor());
+
+        let previewX = stampX;
+        let previewY = stampY - frameRect.height - 8;
+
+        // Clamp to monitor bounds
+        if (previewX + frameRect.width > monGeo.x + monGeo.width)
+            previewX = monGeo.x + monGeo.width - frameRect.width;
+        if (previewX < monGeo.x)
+            previewX = monGeo.x;
+        if (previewY < monGeo.y)
+            previewY = stampY + container.height + 8;
+
+        this._previewContainer.set_position(previewX, previewY);
+        this._topWindowGroup.add_child(this._previewContainer);
+        this._previewClone = clone;
+    }
+
+    _hidePreview() {
+        if (this._previewContainer) {
+            this._previewContainer.destroy();
+            this._previewContainer = null;
+            this._previewClone = null;
+        }
+    }
+
     reparentForDrag(container) {
+        this._hidePreview();
         this._stampLayer.set_child_above_sibling(container, null);
     }

     reparentFromDrag(container) {
-        // No-op — container stays in stamp layer
+        // no-op — container stays in stamp layer
     }

     suspend() {
+        this._hidePreview();
         this._stampLayer.visible = false;
     }

